function hideRubricCritEditor(){rubricCritEditCtx=null;rubricBandsDraft=[];const panel=$("crm-leads-rubric-crit-editor");if(panel)panel.hidden=true;const err=$("crm-leads-rubric-crit-err");if(err)err.hidden=true;}
function fillRubricEvaluatorSelect(sel,val){if(!sel)return;sel.innerHTML=scoringEvaluators.map((e)=>`<option value="${esc(e.id)}">${esc(e.label)}</option>`).join("");if(val&&[...sel.options].some((o)=>o.value===val))sel.value=val;}
function renderRubricBandsEditor(){const body=$("crm-leads-rubric-bands-body");if(!body)return;body.innerHTML=rubricBandsDraft.map((b,idx)=>`<tr data-band-idx="${idx}">
          <td><input type="text" class="crm-rubric-band-label" value="${esc(String(b.label || ""))}" maxlength="120" /></td>
          <td><input type="number" class="crm-rubric-band-min" step="any" value="${b.min_value != null ? esc(String(b.min_value)) : ""}" placeholder="—" /></td>
          <td><input type="number" class="crm-rubric-band-max" step="any" value="${b.max_value != null ? esc(String(b.max_value)) : ""}" placeholder="—" /></td>
          <td><input type="number" class="crm-rubric-band-points" min="0" max="100" value="${Number(b.points ?? 0)}" /></td>
          <td><input type="text" class="crm-rubric-band-extra" value="${esc(String((b.match_sources || []).join(", ") || (b.tier_value != null ? b.tier_value : "")))}" placeholder="tier / nguồn" /></td>
          <td><button type="button" class="btn-secondary btn-xs crm-rubric-band-del" data-idx="${idx}">Xóa</button></td>
        </tr>`,).join("");body.querySelectorAll(".crm-rubric-band-del").forEach((btn)=>{btn.addEventListener("click",()=>{rubricBandsDraft.splice(Number(btn.dataset.idx),1);renderRubricBandsEditor();});});}
function readRubricBandsFromEditor(){const body=$("crm-leads-rubric-bands-body");if(!body)return[];const ev=$("crm-leads-rubric-crit-evaluator")?.value||"";return[...body.querySelectorAll("tr[data-band-idx]")].map((row,idx)=>{const prev=rubricBandsDraft[idx]||{};const minRaw=row.querySelector(".crm-rubric-band-min")?.value;const maxRaw=row.querySelector(".crm-rubric-band-max")?.value;const extra=(row.querySelector(".crm-rubric-band-extra")?.value||"").trim();const band={id:String(prev.id||`band_${Date.now()}_${idx}`),label:(row.querySelector(".crm-rubric-band-label")?.value||"").trim(),points:Number(row.querySelector(".crm-rubric-band-points")?.value||0),min_value:minRaw===""?null:Number(minRaw),max_value:maxRaw===""?null:Number(maxRaw),min_exclusive:Boolean(prev.min_exclusive),max_exclusive:Boolean(prev.max_exclusive),};if(ev==="lead_source"){band.match_sources=extra?extra.split(",").map((s)=>s.trim().toLowerCase()).filter(Boolean):(prev.match_sources||[]);}else if(extra!==""&&!Number.isNaN(Number(extra))){band.tier_value=Number(extra);}
return band;}).filter((b)=>b.label);}
function openRubricCritEditor(groupIdx,critIdx){const groups=scoringRubricDraft.groups||[];const g=groups[groupIdx];if(!g)return;rubricCritEditCtx={groupIdx,critIdx};const isNew=critIdx==null;const c=isNew?{id:`crit_${Date.now()}`,code:"",label:"",evaluator:scoringEvaluators[0]?.id||"info_completeness",max_points:5,enabled:true,bands:[]}:{...(g.criteria[critIdx]||{})};rubricBandsDraft=Array.isArray(c.bands)?c.bands.map((b)=>({...b})):[];$("crm-leads-rubric-crit-title").textContent=isNew?"Thêm tiêu chí":`Sửa ${c.code || c.label || ""}`;$("crm-leads-rubric-crit-code").value=String(c.code||"");$("crm-leads-rubric-crit-label").value=String(c.label||"");fillRubricEvaluatorSelect($("crm-leads-rubric-crit-evaluator"),String(c.evaluator||""));$("crm-leads-rubric-crit-max").value=String(c.max_points??5);$("crm-leads-rubric-crit-enabled").checked=c.enabled!==false;renderRubricBandsEditor();const panel=$("crm-leads-rubric-crit-editor");if(panel){panel.hidden=false;panel.scrollIntoView({behavior:"smooth",block:"nearest"});}
$("crm-leads-rubric-crit-err").hidden=true;}
function saveRubricCritEditor(){if(!rubricCritEditCtx)return true;const{groupIdx,critIdx}=rubricCritEditCtx;const g=(scoringRubricDraft.groups||[])[groupIdx];if(!g)return false;if(!Array.isArray(g.criteria))g.criteria=[];const bands=readRubricBandsFromEditor();if(!bands.length){const err=$("crm-leads-rubric-crit-err");if(err){err.textContent="Cần ít nhất một mức điểm.";err.hidden=false;}
return false;}
const label=($("crm-leads-rubric-crit-label")?.value||"").trim();if(!label){const err=$("crm-leads-rubric-crit-err");if(err){err.textContent="Nhập tên tiêu chí.";err.hidden=false;}
return false;}
const item={id:critIdx!=null?String(g.criteria[critIdx]?.id||`crit_${Date.now()}`):`crit_${Date.now()}`,code:($("crm-leads-rubric-crit-code")?.value||"").trim(),label,evaluator:$("crm-leads-rubric-crit-evaluator")?.value||"info_completeness",max_points:Number($("crm-leads-rubric-crit-max")?.value||0),enabled:$("crm-leads-rubric-crit-enabled")?.checked!==false,sort_order:critIdx!=null?Number(g.criteria[critIdx]?.sort_order??99):(g.criteria.length+1),bands,};if(critIdx!=null)g.criteria[critIdx]=item;else g.criteria.push(item);hideRubricCritEditor();renderScoringRubric();return true;}
function renderScoringRubric(){const root=$("crm-leads-rubric-groups");if(!root)return;const groups=scoringRubricDraft.groups||[];root.innerHTML=groups.slice().sort((a,b)=>Number(a.sort_order??99)-Number(b.sort_order??99)).map((g)=>{const gi=groups.indexOf(g);const crits=Array.isArray(g.criteria)?g.criteria:[];const rows=crits.slice().sort((a,b)=>Number(a.sort_order??99)-Number(b.sort_order??99)).map((c)=>{const ci=(g.criteria||[]).indexOf(c);const bands=Array.isArray(c.bands)?c.bands.length:0;return`<tr>
              <td class="crm-staff-td-mono">${esc(String(c.code || ""))}</td>
              <td><strong>${esc(String(c.label || ""))}</strong>${c.enabled === false ? ' <span class="muted">(tắt)</span>' : ""}</td>
              <td class="muted">${esc(evaluatorLabel(c.evaluator))}</td>
              <td>${Number(c.max_points ?? 0)}</td>
              <td>${bands} mức</td>
              <td class="crm-leads-scoring-actions">
                <button type="button" class="btn-secondary btn-xs crm-leads-rubric-crit-edit" data-gi="${gi}" data-ci="${ci}">Sửa</button>
                <button type="button" class="btn-secondary btn-xs crm-leads-rubric-crit-del" data-gi="${gi}" data-ci="${ci}">Xóa</button>
              </td>
            </tr>`;}).join("");return`<section class="crm-leads-rubric-group">
          <header class="crm-leads-rubric-group-head">
            <div>
              <p class="crm-staff-level-kicker">NHÓM ${esc(String(g.code || ""))} · ${Number(g.max_points ?? 0)} ĐIỂM</p>
              <h3>${esc(String(g.label || ""))}</h3>
            </div>
            <div>
              <button type="button" class="btn-secondary btn-sm crm-leads-rubric-add-crit" data-gi="${gi}">＋ Tiêu chí</button>
              ${groups.length > 1 ? `<button type="button"class="btn-secondary btn-sm crm-leads-rubric-del-group"data-gi="${gi}">Xóa nhóm</button>` : ""}
            </div>
          </header>
          <div class="crm-leads-scoring-table-wrap">
            <table class="crm-leads-scoring-table">
              <thead><tr><th>Mã</th><th>Tiêu chí</th><th>Chỉ số</th><th>Max</th><th>Mức</th><th></th></tr></thead>
              <tbody>${rows || '<tr><td colspan="6" class="muted">Chưa có tiêu chí.</td></tr>'}</tbody>
            </table>
          </div>
        </section>`;}).join("");}
function handleRubricGroupsClick(ev){const addCrit=ev.target.closest(".crm-leads-rubric-add-crit");if(addCrit){openRubricCritEditor(Number(addCrit.dataset.gi),null);return;}
const editBtn=ev.target.closest(".crm-leads-rubric-crit-edit");if(editBtn){openRubricCritEditor(Number(editBtn.dataset.gi),Number(editBtn.dataset.ci));return;}
const delBtn=ev.target.closest(".crm-leads-rubric-crit-del");if(delBtn){const gi=Number(delBtn.dataset.gi);const ci=Number(delBtn.dataset.ci);const c=scoringRubricDraft.groups?.[gi]?.criteria?.[ci];if(!c||!confirm(`Xóa tiêu chí «${c.label}»?`))return;scoringRubricDraft.groups[gi].criteria.splice(ci,1);renderScoringRubric();return;}
const delGroup=ev.target.closest(".crm-leads-rubric-del-group");if(delGroup){const gi=Number(delGroup.dataset.gi);const g=scoringRubricDraft.groups?.[gi];if(!g||!confirm(`Xóa nhóm «${g.label}»?`))return;scoringRubricDraft.groups.splice(gi,1);renderScoringRubric();}}
function handleTiersTableClick(ev){const editBtn=ev.target.closest(".crm-leads-tier-edit");if(editBtn){openTierEditor(Number(editBtn.dataset.idx));return;}
const delBtn=ev.target.closest(".crm-leads-tier-del");if(delBtn){deleteLevelTier(Number(delBtn.dataset.idx));}}
function handleTiersTableChange(ev){const el=ev.target.closest(".crm-leads-tier-enabled");if(!el)return;const i=Number(el.dataset.idx);if(levelTiersDraft[i])levelTiersDraft[i].enabled=el.checked;}
